queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?room_number ?capacity WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasClassrooms ?child ; p:hasTeachers ?parent . } GROUP BY ?child }
  ?child p:room_number ?room_number .
  ?child p:capacity ?capacity .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Teachers } }
  FILTER(?nf = ?total)
}

