ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?room_number ?capacity WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasClassrooms ?child ; p:hasTeachers ?parent . } GROUP BY ?child }
  ?child p:room_number ?room_number .
  ?child p:capacity ?capacity .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Teachers } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?full_name ?room_number ?capacity WHERE {
  ?teachers_classrooms a :Teachers_Classrooms .
  ?classrooms a :Classrooms .
  ?teachers_classrooms p:hasClassrooms ?classrooms .
  ?teachers a :Teachers .
  ?teachers_classrooms p:hasTeachers ?teachers .
  ?teachers p:name ?full_name .
  ?classrooms p:room_number ?room_number .
  ?classrooms p:capacity ?capacity .
} }
}

